<span class="line"><span style="color:#ABB2BF;">		</span><span style="color:#E5C07B;">System</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">out</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">println</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">5</span><span style="color:#56B6C2;">/</span><span style="color:#D19A66;">2.0</span><span style="color:#ABB2BF;">);</span></span>
