<span class="line"><span style="color:#ABB2BF;">        a </span><span style="color:#56B6C2;">=</span><span style="color:#ABB2BF;"> (</span><span style="color:#C678DD;">byte</span><span style="color:#ABB2BF;">) (a</span><span style="color:#56B6C2;">+</span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">);</span></span>
